Read TEEG structure from an open CNT file.

# from TEEG structure in http://paulbourke.net/dataformats/eeg/
typedef struct {
   char Teeg;       /* Either 1 or 2                    */
   long Size;       /* Total length of all the events   */
   long Offset;     /* Hopefully always 0               */
} TEEG;
